import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void typicalCase() {
        // FOOD=700 (500+200), RIDE=300 => top-2: [FOOD, RIDE]
        String[][] txns = {{"FOOD","500"},{"RIDE","300"},{"FOOD","200"}};
        assertEquals(List.of("FOOD","RIDE"), new Solution().topCategoriesByTotalSpend(txns, 2));
    }

    @Test
    void tiebreakByNameAscending() {
        // A=100, B=100, C=50; A and B tie; lex asc: A < B; top-2: [A,B]
        String[][] txns = {{"A","100"},{"B","100"},{"C","50"}};
        assertEquals(List.of("A","B"), new Solution().topCategoriesByTotalSpend(txns, 2));
    }

    @Test
    void threeWayTieTopTwo() {
        // DINING=400, GAS=400, TRAVEL=400; lex asc: DINING < GAS < TRAVEL; top-2: [DINING,GAS]
        String[][] txns = {{"TRAVEL","400"},{"GAS","400"},{"DINING","400"}};
        assertEquals(List.of("DINING","GAS"), new Solution().topCategoriesByTotalSpend(txns, 2));
    }

    @Test
    void kEqualsDistinctCount() {
        // SHOPPING=600, FOOD=300, GAS=100 => k=3: [SHOPPING,FOOD,GAS]
        String[][] txns = {{"SHOPPING","600"},{"FOOD","300"},{"GAS","100"}};
        assertEquals(List.of("SHOPPING","FOOD","GAS"), new Solution().topCategoriesByTotalSpend(txns, 3));
    }

    @Test
    void kExceedsDistinctCount() {
        // k=5 but only 1 category => [GAS]
        String[][] txns = {{"GAS","400"}};
        assertEquals(List.of("GAS"), new Solution().topCategoriesByTotalSpend(txns, 5));
    }

    @Test
    void emptyInput() {
        assertEquals(List.of(), new Solution().topCategoriesByTotalSpend(new String[][]{}, 2));
    }

    @Test
    void multipleTransactionsPerCategory() {
        // UTIL=50+50+50=150, FOOD=80+80=160, RIDE=200 => desc: RIDE(200),FOOD(160),UTIL(150) => top-2: [RIDE,FOOD]
        String[][] txns = {{"UTIL","50"},{"FOOD","80"},{"RIDE","200"},{"UTIL","50"},{"FOOD","80"},{"UTIL","50"}};
        assertEquals(List.of("RIDE","FOOD"), new Solution().topCategoriesByTotalSpend(txns, 2));
    }
}
